CREATE TABLE leave_requests (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), employee_id UUID NOT NULL REFERENCES employees(id) ON DELETE CASCADE, policy_id UUID NOT NULL REFERENCES leave_policies(id) ON DELETE CASCADE, start_date DATE NOT NULL, end_date DATE NOT NULL, total_days DECIMAL(5,2) NOT NULL CHECK (total_days > 0), reason TEXT, status VARCHAR(20) DEFAULT 'draft' CHECK (status IN ('draft', 'submitted', 'pending_approval', 'approved', 'rejected', 'cancelled')), manager_id UUID REFERENCES employees(id), manager_notes TEXT, submitted_at TIMESTAMP, decided_at TIMESTAMP, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);

