CREATE TABLE notifications (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), recipient_id UUID NOT NULL REFERENCES employees(id), type VARCHAR(50) NOT NULL, title VARCHAR(255) NOT NULL, body TEXT NOT NULL, related_entity_type VARCHAR(50), related_entity_id UUID, status VARCHAR(20) DEFAULT 'created' CHECK (status IN ('created', 'sent', 'read', 'archived')), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, read_at TIMESTAMP, archived_at TIMESTAMP);"}

